sql:
SELECT T1.team_name, T1.founded_year, T2.city
FROM teams AS T1
JOIN venues AS T2 ON T1.home_venue = T2.venue_name;

SELECT team_name, COUNT(*) AS match_count
FROM teams
GROUP BY team_name;

SELECT AVG(runs) AS average_runs
FROM player_match_performance
WHERE runs > 50;

SELECT COUNT(*) AS match_count
FROM matches m
JOIN (
  SELECT home_venue FROM teams WHERE team_id = 1
) t ON m.venue = t.home_venue
WHERE m.team1_id = 1 OR m.team2_id = 1;

external_knowledge:
golden threshold of 50 runs: refers to the average runs per player in matches being more than 50;
celestial arena of cricket: metaphorical expression for the cricket matches;
warriors: refers to the players in the cricket teams;
